function slugify(value) {
  return String(value || '')
    .toLowerCase()
    .trim()
    .replace(/https?:\/\//g, '')
    .replace(/www\./g, '')
    .replace(/\.[a-z]{2,}.*$/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80);
}

const incoming = $json.body || $json;
const toolName = incoming.tool_name || incoming.name || incoming.tool || incoming.product_name || '';
const officialUrl = incoming.official_url || incoming.website_url || incoming.url || '';
const slug = slugify(incoming.tool_slug || incoming.slug || toolName || officialUrl || 'unknown-tool');
const sourceText = String(incoming.source_text || incoming.raw_text || incoming.evidence_file || incoming.markdown || incoming.notes || '').slice(0, 90000);

if (!toolName && !officialUrl && !sourceText) {
  throw new Error('Missing intake data. Send at least tool_name, official_url, or source_text.');
}

const normalized = {
  workflow_name: 'NCR Intelligence Vault Evidence Pipeline',
  run_type: incoming.run_type || 'evidence_intake',
  tool: {
    slug,
    name: toolName || slug.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase()),
    category: incoming.category || incoming.tool_category || 'no-code / AI builder',
    official_url: officialUrl,
    affiliate_url: incoming.affiliate_url || '',
    metadata: {
      intake_source: incoming.intake_source || 'n8n_webhook',
      requested_pages: incoming.requested_pages || ['review', 'public_evidence', 'comparison_seed'],
      commercial_priority: incoming.commercial_priority || 'high',
      audience: incoming.audience || 'founders, builders, agencies, and non-technical product creators'
    }
  },
  source: {
    source_type: incoming.source_type || 'submitted_evidence',
    source_url: incoming.source_url || officialUrl || '',
    source_title: incoming.source_title || `${toolName || slug} submitted evidence`,
    publisher: incoming.publisher || '',
    raw_text_excerpt: sourceText.slice(0, 5000)
  },
  source_text: sourceText,
  user_project_context: incoming.user_project_context || incoming.project_context || '',
  monetization_context: incoming.monetization_context || 'Recommend tools only when they solve user pain points. Prefer affiliate-tracked links where available, but preserve trust with clear disclosures and evidence-backed recommendations.',
  quality_rules: {
    min_sources_for_publish: 2,
    min_evidence_items_for_publish: 8,
    min_claims_for_publish: 5,
    min_score_for_publish: 85,
    auto_publish: false
  }
};

const prompt = `You are the NoCodeReviewed Intelligence Vault evidence analyst. Convert the intake into a structured evidence bundle that can power public reviews, comparisons, tutorials, recommendations, and the Vibe Auditor.

Rules:
- Return ONLY valid JSON. No markdown.
- Evidence must be conservative, specific, and traceable.
- Do not invent pricing, features, benchmarks, dates, integrations, security posture, or affiliate claims. If unknown, mark it as unknown or needs_review.
- Every recommendation must connect a user pain point to evidence.
- Monetization is important, but trust is more important. Use affiliate disclosure language when affiliate_url exists.
- Produce public evidence items that can be shown transparently on /evidence/{tool_slug}.

Required JSON shape:
{
  "workflow_name": "NCR Intelligence Vault Evidence Pipeline",
  "run_type": "evidence_intake",
  "tool": {"slug": "...", "name": "...", "category": "...", "official_url": "...", "affiliate_url": "...", "metadata": {}},
  "sources": [{"source_type": "official|docs|pricing|review|submitted_evidence|github|other", "source_url": "...", "source_title": "...", "publisher": "...", "source_quality_score": 0-100, "raw_text_excerpt": "short supporting excerpt", "metadata": {}}],
  "evidence_items": [{"source_url": "...", "evidence_type": "pricing|feature|security|integration|limit|workflow|performance|support|use_case|risk|monetization", "extracted_claim": "specific claim", "raw_excerpt": "short excerpt or note", "confidence_score": 0-100, "freshness_score": 0-100, "contradiction_status": "unchecked|clear|possible_conflict", "public_visibility": true, "metadata": {}}],
  "claims": [{"claim_category": "positioning|best_for|avoid_if|pricing|security|automation|workflow|monetization", "claim_text": "claim for review page", "confidence_score": 0-100, "evidence_count": 0, "metadata": {}}],
  "scores": [{"dimension": "launch_readiness|builder_power|ease_of_use|automation|security|pricing_clarity|evidence_confidence|monetization_fit|overall", "score": 0-100, "reason": "short evidence-backed reason", "evidence_claims": []}],
  "pain_point_matches": [{"pain_point_slug": "build-mvp-fast", "match_score": 0-100, "reason": "why this tool fits or does not fit", "evidence_claims": []}],
  "content_pages": [{"page_type": "tool_review|public_evidence|comparison_seed|tutorial_seed", "slug": "/tools/{tool_slug}", "title": "...", "status": "draft|needs_review|ready_for_publish", "content_json": {}}]
}

Normalized intake:
${JSON.stringify(normalized, null, 2)}

Source/evidence text:
${sourceText || '(No long source text provided. Build a conservative skeleton and mark unknowns.)'}
`;

return [{ json: { ...normalized, prompt } }];

function extractJsonText(response) {
  if (typeof response === 'string') return response;
  return response?.candidates?.[0]?.content?.parts?.[0]?.text
    || response?.candidates?.[0]?.content?.parts?.map(p => p.text || '').join('')
    || response?.text
    || response?.data
    || JSON.stringify(response);
}

function parsePossiblyFencedJson(text) {
  const cleaned = String(text || '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
  try { return JSON.parse(cleaned); } catch (e) {}
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  if (first >= 0 && last > first) return JSON.parse(cleaned.slice(first, last + 1));
  throw new Error('Gemini did not return parseable JSON. Raw text starts: ' + cleaned.slice(0, 400));
}

function arr(value) { return Array.isArray(value) ? value : []; }
function num(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? Math.max(0, Math.min(100, n)) : fallback;
}
function slugify(value) {
  return String(value || 'unknown-tool').toLowerCase().trim().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 80);
}

const ai = parsePossiblyFencedJson(extractJsonText($json));
const tool = ai.tool || {};
tool.slug = slugify(tool.slug || ai.tool_slug || tool.name);
tool.name = tool.name || tool.slug.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
tool.category = tool.category || 'no-code / AI builder';
tool.metadata = tool.metadata || {};

const sources = arr(ai.sources);
const evidence = arr(ai.evidence_items);
const claims = arr(ai.claims);
const scores = arr(ai.scores);
const pages = arr(ai.content_pages);
const painMatches = arr(ai.pain_point_matches);

const issues = [];
let score = 100;
const officialSources = sources.filter(s => /official|docs|pricing|github/i.test(String(s.source_type || '') + ' ' + String(s.publisher || '') + ' ' + String(s.source_url || ''))).length;

if (sources.length < 1) { score -= 30; issues.push('No source records generated.'); }
if (sources.length < 2) { score -= 10; issues.push('Needs at least two sources before publication.'); }
if (officialSources < 1) { score -= 15; issues.push('Needs at least one official/docs/pricing/GitHub source.'); }
if (evidence.length < 5) { score -= 20; issues.push('Too few evidence items for a reliable public review.'); }
if (evidence.length < 8) { score -= 8; issues.push('Below recommended evidence depth for auto-ready publishing.'); }
if (claims.length < 3) { score -= 10; issues.push('Too few review claims generated.'); }
if (!evidence.some(e => /pricing|cost|plan/i.test(String(e.evidence_type || '') + ' ' + String(e.extracted_claim || '')))) {
  score -= 8; issues.push('Pricing evidence is missing or unclear.');
}
if (!scores.some(s => s.dimension === 'overall')) {
  scores.push({ dimension: 'overall', score: Math.max(0, score), reason: 'Computed by gateway fallback from evidence completeness.', evidence_claims: [] });
}
const hypeClaims = claims.filter(c => /best|perfect|guaranteed|revolutionary|ultimate/i.test(String(c.claim_text || '')) && num(c.confidence_score, 0) < 80);
if (hypeClaims.length) { score -= 10; issues.push('Potential hype claims need stronger evidence or softer wording.'); }

score = Math.max(0, Math.min(100, Math.round(score)));
const status = score >= 85 ? 'ready_for_publish' : score >= 60 ? 'needs_review' : 'blocked';

const defaultPages = [
  {
    page_type: 'tool_review',
    slug: `/tools/${tool.slug}`,
    title: `${tool.name} Review: Evidence, Best Use Cases, Limits, and Alternatives`,
    status,
    content_json: { tool, summary: ai.summary || '', claims, scores, pain_point_matches: painMatches, monetization: ai.monetization || {}, disclosure: tool.affiliate_url ? 'Some links may be affiliate links. Recommendations are based on evidence and fit, not commissions.' : '' }
  },
  {
    page_type: 'public_evidence',
    slug: `/evidence/${tool.slug}`,
    title: `${tool.name} Public Evidence File`,
    status: score >= 60 ? 'ready_for_publish' : 'needs_review',
    content_json: { tool, sources, evidence_items: evidence, quality_gate: { score, status, issues } }
  },
  {
    page_type: 'comparison_seed',
    slug: `/compare/${tool.slug}-alternatives`,
    title: `${tool.name} Alternatives and Best-Fit Comparisons`,
    status: 'draft',
    content_json: { tool, pain_point_matches: painMatches, scores, comparison_angle: ai.comparison_angle || '' }
  }
];

const bundle = {
  workflow_name: 'NCR Intelligence Vault Evidence Pipeline',
  run_type: ai.run_type || 'evidence_intake',
  tool,
  sources,
  evidence_items: evidence,
  claims,
  scores,
  pain_point_matches: painMatches,
  content_pages: pages.length ? pages : defaultPages,
  evidence_confidence: score,
  quality_gate: {
    target_type: 'tool_review',
    score,
    status,
    issues,
    metadata: {
      source_count: sources.length,
      official_source_count: officialSources,
      evidence_item_count: evidence.length,
      claim_count: claims.length,
      generated_at: new Date().toISOString()
    }
  }
};

return [{ json: { bundle, response_preview: { tool_slug: tool.slug, tool_name: tool.name, quality_score: score, quality_status: status, issues } } }];
